print "Output length: " . length($output_seq) . "\n";

# Find differences
if (length($input_seq) == length($output_seq)) {
    my @diffs;
    for my $i (0..length($input_seq)-1) {
        if (substr($input_seq, $i, 1) ne substr($output_seq, $i, 1)) {
            push @diffs, $i;
        }
    }
    print "Number of SNPs: " . scalar(@diffs) . "\n";
} else {
    # Find first and last mismatch
    my $min_len = length($input_seq) < length($output_seq) ? length($input_seq) : length($output_seq);
    my $first_diff = undef;
    my $last_diff = undef;
    for my $i (0..$min_len-1) {
        if (substr($input_seq, $i, 1) ne substr($output_seq, $i, 1)) {
            $first_diff = $i unless defined $first_diff;
            $last_diff = $i;
        }
    }

    print "First diff at position: " . ($first_diff // 'none') . "\n";
    print "Last diff at position: " . ($last_diff // 'none') . "\n";

    if (defined $first_diff) {
        my $start = $first_diff > 20 ? $first_diff - 20 : 0;
        my $end = $first_diff + 30;
        print "\nAround first diff:\n";
        print "Input:  " . substr($input_seq, $start, $end - $start) . "\n";
        print "Output: " . substr($output_seq, $start, $end - $start) . "\n";
    }

    if (defined $last_diff) {
        my $start = $last_diff > 20 ? $last_diff - 20 : 0;
        my $end = $last_diff + 30;
        print "\nAround last diff:\n";
        print "Input:  " . substr($input_seq, $start, $end - $start) . "\n";
        print "Output: " . substr($output_seq, $start, $end - $start) . "\n";
    }

    # Check if output is longer (insertion) or shorter (deletion)
    my $len_diff = length($output_seq) - length($input_seq);
    print "\nLength difference: $len_diff\n";
}

# Show the sequences around the difference region more carefully
if (length($input_seq) != length($output_seq)) {
    # Try to find the exact insertion point
    # Look for where they diverge and reconverge
    my $min_len = length($input_seq) < length($output_seq) ? length($input_seq) : length($output_seq);

    # Find first mismatch from start
    my $start_mismatch = 0;
    while ($start_mismatch < $min_len && substr($input_seq, $start_mismatch, 1) eq substr($output_seq, $start_mismatch, 1)) {
        $start_mismatch++;
    }

    # Find first mismatch from end
    my $end_mismatch_input = length($input_seq) - 1;
    my $end_mismatch_output = length($output_seq) - 1;
    while ($end_mismatch_input >= 0 && $end_mismatch_output >= 0 && 
           substr($input_seq, $end_mismatch_input, 1) eq substr($output_seq, $end_mismatch_output, 1)) {
        $end_mismatch_input--;
        $end_mismatch_output--;
    }

    print "\n=== Divergence region ===\n";
    print "Start mismatch (input): $start_mismatch\n";
    print "End mismatch (input): $end_mismatch_input\n";
    print "End mismatch (output): $end_mismatch_output\n";

    my $input_region = substr($input_seq, $start_mismatch, $end_mismatch_input - $start_mismatch + 1);
