    # Forward primer annealing region: input[215 .. 215+len-1]
    my $f_anno = substr($input_seq, 215, $len);

    # Reverse primer annealing region: we need to go backwards from position 214
    # The reverse primer anneals at positions [214-len+1 .. 214] (wrapping if needed)
    my $r_start = 215 - $len;  # This is the start of the reverse primer's annealing region
    if ($r_start < 0) {
        # Circular: wrap around
        # Positions from (plasmid_len + r_start) to plasmid_len-1, then 0 to (214 - (plasmid_len + r_start))
        my $wrap_start = $plasmid_len + $r_start;
        my $r_anno = substr($input_seq, $wrap_start) . substr($input_seq, 0, 215 - $wrap_start);
