        next;  # Skip if it would wrap (shouldn't happen for len <= 45 and start at 215)
    }

    my $r_anno = substr($input_seq, $r_start, $len);

    # Build primers
    my $f_primer = $insertion . $f_anno;
    my $r_primer = revcomp($insertion) . revcomp($r_anno);

    # Get Tm using oligotm for just the annealing regions
    my $f_tm_cmd = "oligotm -tp 1 -sc 1 -mv 50 -dv 2 -n 0.8 -d 500 \"$f_anno\"";
    my $r_tm_cmd = "oligotm -tp 1 -sc 1 -mv 50 -dv 2 -n 0.8 -d 500 \"$r_anno\"";

    open(my $ft, '-|', $f_tm_cmd) or next;
    my $f_tm = <$ft>;
    close($ft);

    open(my $rt, '-|', $r_tm_cmd) or next;
    my $r_tm = <$rt>;
    close($rt);

    chomp $f_tm;
    chomp $r_tm;

    $f_tm += 0;
    $r_tm += 0;

    my $tm_diff = abs($f_tm - $r_tm);

    # Check constraints
    if ($f_tm >= 58 && $f_tm <= 72 && $r_tm >= 58 && $r_tm <= 72 && $tm_diff <= 5) {
